			$locations,
			static function ( $id_a, $id_b ) use ( $locations ) {
				$cmp = strnatcasecmp( (string) $locations[ $id_a ], (string) $locations[ $id_b ] );
				return 0 !== $cmp ? $cmp : strcmp( $id_a, $id_b );
			}
		)

array_filter( $classes, function ( $class ) use ( $blocklist ) {
					if ( in_array( $class, $blocklist, true ) ) {
						return false;
					}
					if ( preg_match( '/^(mega-)?menu-item-(type|object)-/', $class ) ) {
						return false;
					}
					if ( preg_match( '/^(mega-)?menu-item-\d+$/', $class ) ) {
						return false;
					}
					if ( preg_match( '/^(mega-)?page-item-\d+$/', $class ) ) {
						return false;
					}
					return true;
				} )

